import * as THREE from 'three';

export class TreeLayer {
  meshes: THREE.Mesh[] = [];
  constructor(private scene: THREE.Scene, private geom: THREE.BufferGeometry, private mat: THREE.Material) {}

  load(trees: {id: string; x: number; y: number; z: number; carbon: number}[]) {
    for (const t of trees) {
      const m = new THREE.Mesh(this.geom, this.mat.clone());
      m.position.set(t.x, t.y, t.z);
      (m.material as THREE.MeshStandardMaterial).color.set(carbonColor(t.carbon));
      m.userData.id = t.id;
      this.scene.add(m);
      this.meshes.push(m);
    }
  }

  pick(raycaster: THREE.Raycaster): string | null {
    const hit = raycaster.intersectObjects(this.meshes)[0];
    return hit ? (hit.object.userData.id as string) : null;
  }
}

function carbonColor(c: number) { return c > 50 ? 0x1b7837 : 0xa6dba0; }

import * as THREE from 'three';

export class TreeLayer {
  private mesh!: THREE.InstancedMesh;
  private idByInstance: string[] = [];
  private instanceById = new Map<string, number>();
  private dummy = new THREE.Object3D();

  constructor(private scene: THREE.Scene, private geom: THREE.BufferGeometry, private mat: THREE.MeshStandardMaterial) {}

  load(trees: {id: string; x: number; y: number; z: number; carbon: number}[]) {
    const n = trees.length;
    this.mesh = new THREE.InstancedMesh(this.geom, this.mat, n);
    this.mesh.instanceMatrix.setUsage(THREE.DynamicDrawUsage);
    const color = new THREE.Color();
    this.idByInstance = new Array(n);
    for (let i = 0; i < n; i++) {
      const t = trees[i];
      this.dummy.position.set(t.x, t.y, t.z);
      this.dummy.updateMatrix();
      this.mesh.setMatrixAt(i, this.dummy.matrix);
      this.mesh.setColorAt(i, color.set(carbonColor(t.carbon)));
      this.idByInstance[i] = t.id;
      this.instanceById.set(t.id, i);
    }
    this.mesh.instanceMatrix.needsUpdate = true;
    this.mesh.instanceColor!.needsUpdate = true;
    this.scene.add(this.mesh);
  }

  pick(raycaster: THREE.Raycaster): string | null {
    const hit = raycaster.intersectObject(this.mesh)[0];
    return hit && hit.instanceId != null ? this.idByInstance[hit.instanceId] : null;
  }

  highlight(id: string, c: THREE.Color) {
    const i = this.instanceById.get(id);
    if (i == null) return;
    this.mesh.setColorAt(i, c);
    this.mesh.instanceColor!.needsUpdate = true;
  }
}

function carbonColor(c: number) { return c > 50 ? 0x1b7837 : 0xa6dba0; }

import * as THREE from 'three';

// Distance-based LOD: full canopy geometry up close, a 2-tri billboard far away.
export function buildTreeLOD(full: THREE.BufferGeometry, billboard: THREE.BufferGeometry, mat: THREE.Material) {
  const lod = new THREE.LOD();
  lod.addLevel(new THREE.Mesh(full, mat), 0);
  lod.addLevel(new THREE.Mesh(billboard, mat), 2000);
  return lod;
}

// For instanced layers we swap the InstancedMesh geometry on a camera-distance hysteresis
export function pickGeometryForDistance(d: number, full: THREE.BufferGeometry, billboard: THREE.BufferGeometry) {
  return d > 2200 ? billboard : (d < 1800 ? full : null); // null = keep current (hysteresis band)
}

import * as THREE from 'three';
import { TreeLayer } from './TreeLayer';

export function renderFrame(renderer: THREE.WebGLRenderer, scene: THREE.Scene, camera: THREE.Camera, layer: TreeLayer, onFps: (f: number) => void) {
  let last = performance.now();
  const loop = (t: number) => {
    const dt = t - last; last = t;
    onFps(1000 / dt);
    renderer.render(scene, camera);
    requestAnimationFrame(loop);
  };
  requestAnimationFrame(loop);
}

export async function loadCloud(url: string) {
  const buf = await (await fetch(url)).arrayBuffer(); // 9GB
  const view = new DataView(buf);
  const count = view.getUint32(107, true);
  const positions = new Float32Array(count * 3);
  let o = view.getUint32(96, true);
  for (let i = 0; i < count; i++) {
    positions[i*3]   = view.getInt32(o, true) * 0.001;
    positions[i*3+1] = view.getInt32(o+4, true) * 0.001;
    positions[i*3+2] = view.getInt32(o+8, true) * 0.001;
    o += 28;
  }
  return positions; // uploaded as one buffer
}

export interface OctreeNode { id: string; bbox: [number,number,number,number,number,number]; childMask: number; pointCount: number; url: string; }

export class Octree {
  constructor(public root: OctreeNode, private nodes: Map<string, OctreeNode>) {}

  visibleNodes(frustum: Frustum, screenError: (n: OctreeNode) => number, budget = 1_500_000): OctreeNode[] {
    const out: OctreeNode[] = []; const queue = [this.root]; let acc = 0;
    while (queue.length) {
      const n = queue.shift()!;
      if (!frustum.intersectsBox(n.bbox)) continue;
      out.push(n); acc += n.pointCount;
      if (acc > budget) break;
      if (screenError(n) > 1) for (const c of this.children(n)) queue.push(c);
    }
    return out;
  }
  private children(n: OctreeNode): OctreeNode[] {
    const r: OctreeNode[] = [];
    for (let i = 0; i < 8; i++) if (n.childMask & (1<<i)) { const c = this.nodes.get(`${n.id}${i}`); if (c) r.push(c); }
    return r;
  }
}
export interface Frustum { intersectsBox(b: number[]): boolean; }

// Decodes one octree node binary off the main thread
self.onmessage = async (e: MessageEvent<{id: string; url: string}>) => {
  const { id, url } = e.data;
  const buf = await (await fetch(url)).arrayBuffer();
  const dv = new DataView(buf);
  const count = dv.getUint32(0, true);
  const pos = new Float32Array(count * 3);
  const ids = new Uint32Array(count);
  let o = 4;
  for (let i = 0; i < count; i++) {
    pos[i*3]=dv.getInt32(o,true)*0.001; pos[i*3+1]=dv.getInt32(o+4,true)*0.001; pos[i*3+2]=dv.getInt32(o+8,true)*0.001;
    ids[i]=dv.getUint32(o+12,true); o+=16;
  }
  (self as any).postMessage({ id, pos, ids }, [pos.buffer, ids.buffer]);
};

export class NodeBuffers {
  private gpu = new Map<string, { buffer: GPUBuffer; count: number; lastUsed: number }>();
  private bytes = 0;
  constructor(private device: GPUDevice, private capBytes = 1_500_000 * 12) {}

  upload(id: string, pos: Float32Array) {
    if (this.gpu.has(id)) { this.gpu.get(id)!.lastUsed = performance.now(); return; }
    while (this.bytes + pos.byteLength > this.capBytes) this.evictLRU();
    const buffer = this.device.createBuffer({ size: pos.byteLength, usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST });
    this.device.queue.writeBuffer(buffer, 0, pos);
    this.gpu.set(id, { buffer, count: pos.length/3, lastUsed: performance.now() });
    this.bytes += pos.byteLength;
  }
  private evictLRU() {
    let oldest: string | null = null; let t = Infinity;
    for (const [k, v] of this.gpu) if (v.lastUsed < t) { t = v.lastUsed; oldest = k; }
    if (oldest) { const e = this.gpu.get(oldest)!; e.buffer.destroy(); this.bytes -= e.count*12; this.gpu.delete(oldest); }
  }
  visible(): { buffer: GPUBuffer; count: number }[] { return [...this.gpu.values()]; }
}

// WebGL2 fallback for Safari < 18: same node buffers, gl.POINTS draw
export function drawGL(gl: WebGL2RenderingContext, prog: WebGLProgram, nodes: {vbo: WebGLBuffer; count: number}[]) {
  for (const n of nodes) {
    gl.bindBuffer(gl.ARRAY_BUFFER, n.vbo);
    gl.vertexAttribPointer(0, 3, gl.FLOAT, false, 0, 0);
    gl.drawArrays(gl.POINTS, 0, n.count);
  }
}

export class Renderer {
  private gl: WebGLRenderingContext;
  private tex: WebGLTexture;
  private prog: WebGLProgram;
  constructor(canvas: HTMLCanvasElement) {
    this.gl = canvas.getContext('webgl')!;
    this.prog = buildProgram(this.gl);
    this.tex = this.gl.createTexture()!;
  }
  draw(book: Float32Array) {
    const gl = this.gl;
    gl.bindTexture(gl.TEXTURE_2D, this.tex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 256, 256, 0, gl.RGBA, gl.FLOAT, book);
    gl.useProgram(this.prog);
    gl.drawArrays(gl.TRIANGLES, 0, 6);
  }
}

export class Renderer {
  private gl: WebGLRenderingContext;
  private tex: WebGLTexture | null = null;
  private prog: WebGLProgram | null = null;
  private lost = false;
  private latest: Float32Array | null = null;
  private lostExt: WEBGL_lose_context | null;

  constructor(private canvas: HTMLCanvasElement, private onRecover: () => void) {
    this.gl = canvas.getContext('webgl', { powerPreference: 'high-performance' })!;
    this.lostExt = this.gl.getExtension('WEBGL_lose_context');
    canvas.addEventListener('webglcontextlost', (e) => { e.preventDefault(); this.lost = true; }, false);
    canvas.addEventListener('webglcontextrestored', () => { this.buildResources(); this.lost = false; this.onRecover(); }, false);
    this.buildResources();
  }

  private buildResources() {
    const gl = this.gl;
    this.prog = buildProgram(gl);
    this.tex = gl.createTexture();
    if (this.latest) this.draw(this.latest); // replay last known book
  }

  submit(book: Float32Array) { this.latest = book; if (!this.lost) this.draw(book); }

  private draw(book: Float32Array) {
    const gl = this.gl;
    if (gl.isContextLost()) { this.lost = true; return; }
    gl.bindTexture(gl.TEXTURE_2D, this.tex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 256, 256, 0, gl.RGBA, gl.FLOAT, book);
    gl.useProgram(this.prog!);
    gl.drawArrays(gl.TRIANGLES, 0, 6);
  }

  forceRestore() { this.lostExt?.restoreContext(); }
  isLost() { return this.lost; }
}

import { Renderer } from './Renderer';

// If a context loss isn't restored within 2s, force a restore via the lose_context extension.
export function startWatchdog(r: Renderer) {
  let lostSince = 0;
  setInterval(() => {
    if (r.isLost()) {
      if (!lostSince) lostSince = performance.now();
      else if (performance.now() - lostSince > 2000) { r.forceRestore(); lostSince = 0; }
    } else lostSince = 0;
  }, 250);
}

// The websocket lives independently of the renderer so recovery never drops the subscription.
export class BookFeed {
  private ws: WebSocket;
  constructor(url: string, private onSnap: (b: Float32Array) => void) {
    this.ws = new WebSocket(url);
    this.ws.binaryType = 'arraybuffer';
    this.ws.onmessage = (e) => this.onSnap(new Float32Array(e.data));
  }
}

import { useSensors } from './state';

export function Sensors() {
  const sensors = useSensors(); // refetched every 5s, new array identity
  return (
    <group>
      {sensors.map(s => (
        <mesh key={s.id} position={[s.x, s.y, s.z]}>
          <sphereGeometry args={[0.2, 8, 8]} />
          <meshStandardMaterial color={statusColor(s.status)} />
        </mesh>
      ))}
    </group>
  );
}
function statusColor(s: string) { return s === 'alarm' ? 'red' : s === 'warn' ? 'orange' : 'green'; }

import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { sensorStore } from './state';

export function Sensors({ layout }: { layout: {id:string;x:number;y:number;z:number}[] }) {
  const geomRef = useRef<THREE.BufferGeometry>(null!);
  const idIndex = useMemo(() => new Map(layout.map((s,i)=>[s.id,i])), [layout]);
  const geom = useMemo(() => buildMerged(layout), [layout]);

  useFrame(() => {
    const colors = geom.getAttribute('color') as THREE.BufferAttribute;
    let dirty = false;
    for (const id of sensorStore.dirtyIds()) {
      const i = idIndex.get(id); if (i == null) continue;
      const c = statusColor(sensorStore.status(id));
      colors.setXYZ(i, c.r, c.g, c.b); dirty = true;
    }
    if (dirty) { colors.needsUpdate = true; sensorStore.clearDirty(); }
  });

  return <points ref={geomRef as any} geometry={geom}><pointsMaterial vertexColors size={0.4} /></points>;
}

function buildMerged(layout: {x:number;y:number;z:number}[]) {
  const g = new THREE.BufferGeometry();
  const pos = new Float32Array(layout.length*3); const col = new Float32Array(layout.length*3);
  layout.forEach((s,i)=>{ pos[i*3]=s.x; pos[i*3+1]=s.y; pos[i*3+2]=s.z; col[i*3]=0; col[i*3+1]=1; col[i*3+2]=0; });
  g.setAttribute('position', new THREE.BufferAttribute(pos,3));
  g.setAttribute('color', new THREE.BufferAttribute(col,3));
  return g;
}
function statusColor(s: string) { return s==='alarm'?new THREE.Color('red'):s==='warn'?new THREE.Color('orange'):new THREE.Color('green'); }

// Status store lives outside React so polls never trigger reconciliation.
class SensorStore {
  private statuses = new Map<string,string>();
  private dirty = new Set<string>();
  apply(updates: {id:string;status:string}[]) {
    for (const u of updates) if (this.statuses.get(u.id) !== u.status) { this.statuses.set(u.id,u.status); this.dirty.add(u.id); }
  }
  status(id:string){ return this.statuses.get(id) ?? 'ok'; }
  dirtyIds(){ return [...this.dirty]; }
  clearDirty(){ this.dirty.clear(); }
}
export const sensorStore = new SensorStore();

import { sensorStore } from './state';
export function startPolling(url:string){
  setInterval(async()=>{ const r=await fetch(url); sensorStore.apply(await r.json()); }, 5000);
}

import Delaunator from 'delaunator';
import * as THREE from 'three';

export function buildTerrain(points: Float64Array): THREE.BufferGeometry {
  const d = Delaunator.from(chunk(points)); // blocks ~4.2s for 2M points
  const geom = new THREE.BufferGeometry();
  const pos = new Float32Array(points.length);
  for (let i = 0; i < points.length; i++) pos[i] = points[i];
  geom.setIndex(Array.from(d.triangles));
  geom.setAttribute('position', new THREE.BufferAttribute(pos, 3));
  geom.computeVertexNormals();
  return geom;
}
function chunk(p: Float64Array){ const out:[number,number][]=[]; for(let i=0;i<p.length;i+=3) out.push([p[i],p[i+2]]); return out; }

import * as THREE from 'three';

export class TerrainBuilder {
  private worker = new Worker(new URL('./triangulate.worker.ts', import.meta.url), { type: 'module' });
  constructor(private geom: THREE.BufferGeometry) {}

  build(points: Float64Array): Promise<void> {
    const n = points.length;
    const sharedPts = new SharedArrayBuffer(n * 8);
    new Float64Array(sharedPts).set(points);
    const sharedIdx = new SharedArrayBuffer(n * 6 * 4); // generous upper bound
    const meta = new Int32Array(new SharedArrayBuffer(8));
    return new Promise((res) => {
      this.worker.onmessage = () => {
        const triCount = meta[0];
        this.geom.setIndex(new THREE.BufferAttribute(new Uint32Array(sharedIdx, 0, triCount), 1));
        this.geom.setAttribute('position', new THREE.BufferAttribute(new Float32Array(toF32(sharedPts)), 3));
        this.geom.attributes.position.needsUpdate = true;
        res();
      };
      this.worker.postMessage({ sharedPts, sharedIdx, meta, count: n / 3 });
    });
  }
}
function toF32(sab: SharedArrayBuffer){ const d=new Float64Array(sab); const f=new Float32Array(d.length); for(let i=0;i<d.length;i++) f[i]=d[i]; return f; }

import Delaunator from 'delaunator';

self.onmessage = (e: MessageEvent) => {
  const { sharedPts, sharedIdx, meta, count } = e.data;
  const pts = new Float64Array(sharedPts);
  const xy: number[] = new Array(count * 2);
  for (let i = 0; i < count; i++) { xy[i*2] = pts[i*3]; xy[i*2+1] = pts[i*3+2]; }
  const d = Delaunator.from(xy, (p:number,_i:number)=>xy[p], (p:number)=>xy[p+1]);
  const out = new Uint32Array(sharedIdx);
  out.set(d.triangles);
  Atomics.store(new Int32Array(meta), 0, d.triangles.length);
  (self as any).postMessage('done');
};

// Required for SharedArrayBuffer in browsers
export function crossOriginIsolation(_req:any, res:any, next:any){
  res.setHeader('Cross-Origin-Opener-Policy','same-origin');
  res.setHeader('Cross-Origin-Embedder-Policy','require-corp');
  next();
}

export function uvForSwatch(index: number, cols = 16, cell = 256, atlas = 4096) {
  const c = index % cols, r = Math.floor(index / cols);
  const u0 = (c * cell) / atlas;
  const v0 = (r * cell) / atlas;
  const u1 = u0 + cell / atlas;
  const v1 = v0 + cell / atlas;
  return { u0, v0, u1, v1 };
}

export interface AtlasMeta { cols: number; padded: number; content: number; gutter: number; atlas: number; }
export const META: AtlasMeta = { cols: 14, padded: 288, content: 256, gutter: 16, atlas: 4096 };

export function uvForSwatch(index: number, m: AtlasMeta = META) {
  const c = index % m.cols, r = Math.floor(index / m.cols);
  const x0 = c * m.padded + m.gutter; // skip the gutter to land on content
  const y0 = r * m.padded + m.gutter;
  const half = 0.5; // half-texel inset
  const u0 = (x0 + half) / m.atlas;
  const v0 = (y0 + half) / m.atlas;
  const u1 = (x0 + m.content - half) / m.atlas;
  const v1 = (y0 + m.content - half) / m.atlas;
  return { u0, v0, u1, v1 };
}

// Re-packs swatches into 288px cells with 16px edge-extruded gutters.
import sharp from 'sharp';

export async function packAtlas(swatches: Buffer[], cols = 14, content = 256, gutter = 16) {
  const padded = content + gutter * 2; const atlas = cols * padded;
  const layers: sharp.OverlayOptions[] = [];
  for (let i = 0; i < swatches.length; i++) {
    const c = i % cols, r = Math.floor(i / cols);
    // extrude edges into the gutter so coarse mips sample the same color, not neighbors
    const extruded = await sharp(swatches[i]).resize(content, content).extend({ top:gutter,bottom:gutter,left:gutter,right:gutter, extendWith:'copy' }).toBuffer();
    layers.push({ input: extruded, left: c*padded, top: r*padded });
  }
  return sharp({ create: { width: atlas, height: atlas, channels: 4, background: '#00000000' } }).composite(layers).png().toBuffer();
}

import * as THREE from 'three';
import { META } from './atlas';

export function makeAtlasTexture(img: HTMLImageElement) {
  const tex = new THREE.Texture(img);
  tex.wrapS = tex.wrapT = THREE.ClampToEdgeWrapping;
  tex.generateMipmaps = true;
  // cap mips so the smallest cell still spans >= 2 content texels
  const maxLevel = Math.floor(Math.log2(META.content)) - 1;
  (tex as any).maxLevel = maxLevel;
  tex.anisotropy = 4;
  tex.needsUpdate = true;
  return tex;
}

export function frame(ctx: Ctx) {
  updateAnimation(ctx);   // must run
  layoutLabels(ctx);      // ~6ms, expensive
  raycastHover(ctx);      // ~3ms
  decodePendingTextures(ctx); // ~10ms spike when textures arrive
  ctx.renderer.render(ctx.scene, ctx.camera);
  requestAnimationFrame(() => frame(ctx));
}

export interface Task { name: string; priority: number; cost: number; run: (budgetMs: number) => void; }

export class FrameScheduler {
  private deferred: Task[] = [];
  private skips = new Map<string, number>();
  constructor(private budgetMs: number, private starveCap = 5) {}

  add(t: Task) { this.deferred.push(t); this.deferred.sort((a,b)=>b.priority-a.priority); }

  run(frameStart: number, critical: () => void) {
    critical();
    for (const t of this.deferred) {
      const used = performance.now() - frameStart;
      const left = this.budgetMs - used;
      const starved = (this.skips.get(t.name) ?? 0) >= this.starveCap;
      if (left > t.cost || starved) { t.run(Math.max(left, t.cost)); this.skips.set(t.name, 0); }
      else this.skips.set(t.name, (this.skips.get(t.name) ?? 0) + 1);
    }
  }
}

import { FrameScheduler } from './scheduler';

export function makeLoop(ctx: Ctx, vr: boolean) {
  const sched = new FrameScheduler(vr ? 11 : 16.6);
  sched.add({ name:'hover', priority:3, cost:3, run:()=>raycastHover(ctx) });
  sched.add({ name:'labels', priority:2, cost:6, run:()=>layoutLabels(ctx) });
  sched.add({ name:'tex', priority:1, cost:4, run:(b)=>decodePendingTextures(ctx, b) });

  const frame = (t: number) => {
    sched.run(t, () => { updateAnimation(ctx); });
    ctx.renderer.render(ctx.scene, ctx.camera);
    requestAnimationFrame(frame);
  };
  requestAnimationFrame(frame);
}

// Bounded texture decode: only decode until the passed budget is spent.
export function decodePendingTextures(ctx: Ctx, budgetMs: number) {
  const start = performance.now();
  while (ctx.pending.length && performance.now() - start < budgetMs) {
    const job = ctx.pending.shift()!; job.upload();
  }
}

export function step(positions: Float32Array, vel: Float32Array, dt: number, gl: WebGL2RenderingContext, vbo: WebGLBuffer) {
  for (let i = 0; i < positions.length; i += 3) {
    positions[i]   += vel[i]   * dt;
    positions[i+1] += vel[i+1] * dt;
    positions[i+2] += vel[i+2] * dt;
    if (positions[i+1] < 0) positions[i+1] = 1; // respawn
  }
  gl.bindBuffer(gl.ARRAY_BUFFER, vbo);
  gl.bufferData(gl.ARRAY_BUFFER, positions, gl.DYNAMIC_DRAW); // 6MB re-upload/frame
}

export class ParticleSim {
  private read: WebGLBuffer; private write: WebGLBuffer;
  private tf: WebGLTransformFeedback;
  constructor(private gl: WebGL2RenderingContext, init: Float32Array, private prog: WebGLProgram, private windTex: WebGLTexture) {
    this.read = this.buf(init); this.write = this.buf(init);
    this.tf = gl.createTransformFeedback()!;
  }
  private buf(data: Float32Array){ const b=this.gl.createBuffer()!; this.gl.bindBuffer(this.gl.ARRAY_BUFFER,b); this.gl.bufferData(this.gl.ARRAY_BUFFER,data,this.gl.DYNAMIC_COPY); return b; }

  step(dt: number) {
    const gl = this.gl;
    gl.useProgram(this.prog);
    gl.uniform1f(gl.getUniformLocation(this.prog,'uDt'), dt);
    gl.activeTexture(gl.TEXTURE0); gl.bindTexture(gl.TEXTURE_2D, this.windTex);
    gl.bindBuffer(gl.ARRAY_BUFFER, this.read);
    gl.vertexAttribPointer(0, 3, gl.FLOAT, false, 0, 0); gl.enableVertexAttribArray(0);
    gl.bindTransformFeedback(gl.TRANSFORM_FEEDBACK, this.tf);
    gl.bindBufferBase(gl.TRANSFORM_FEEDBACK_BUFFER, 0, this.write);
    gl.enable(gl.RASTERIZER_DISCARD);
    gl.beginTransformFeedback(gl.POINTS);
    gl.drawArrays(gl.POINTS, 0, 500000);
    gl.endTransformFeedback();
    gl.disable(gl.RASTERIZER_DISCARD);
    [this.read, this.write] = [this.write, this.read]; // ping-pong
  }
  current(){ return this.read; }
}

#version 300 es
layout(location=0) in vec3 aPos;
uniform float uDt; uniform sampler2D uWind;
out vec3 vPos;
float hash(vec3 p){ return fract(sin(dot(p, vec3(12.9898,78.233,37.719)))*43758.5453); }
void main(){
  vec2 uv = aPos.xz * 0.5 + 0.5;
  vec3 wind = texture(uWind, uv).xyz * 2.0 - 1.0;
  vec3 next = aPos + wind * uDt;
  if (next.y < 0.0) next = vec3(hash(aPos)*2.0-1.0, 1.0, hash(aPos.zyx)*2.0-1.0); // deterministic respawn
  vPos = next;
}

import * as THREE from 'three';
// Link the TF program declaring the captured varying.
export function buildTFProgram(gl: WebGL2RenderingContext, vs: string, fs: string) {
  const p = gl.createProgram()!;
  const v = compile(gl, gl.VERTEX_SHADER, vs); const f = compile(gl, gl.FRAGMENT_SHADER, fs);
  gl.attachShader(p, v); gl.attachShader(p, f);
  gl.transformFeedbackVaryings(p, ['vPos'], gl.SEPARATE_ATTRIBS);
  gl.linkProgram(p);
  return p;
}
function compile(gl: WebGL2RenderingContext, t: number, s: string){ const sh=gl.createShader(t)!; gl.shaderSource(sh,s); gl.compileShader(sh); return sh; }

export class TowerLayer {
  type = 'custom' as const; id = 'towers';
  render(gl: WebGLRenderingContext, matrix: number[]) {
    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
    gl.depthMask(false);
    for (const t of this.towers) t.draw(gl, matrix); // arbitrary order
  }
}

import { OITTargets } from './oit';

export class TowerLayer {
  type = 'custom' as const; id = 'towers';
  private oit!: OITTargets;
  onAdd(map: any, gl: WebGL2RenderingContext) { this.oit = new OITTargets(gl, map.getCanvas()); }

  render(gl: WebGL2RenderingContext, matrix: number[]) {
    const saved = saveGLState(gl);
    this.oit.beginAccum(gl); // bind MRT, additive, depthTest on / depthMask off
    for (const t of this.towers) t.drawWeighted(gl, matrix);
    this.oit.composite(gl); // fullscreen blend over the map framebuffer
    restoreGLState(gl, saved);
  }
}

export class OITTargets {
  private accum: WebGLTexture; private reveal: WebGLTexture; private fbo: WebGLFramebuffer;
  constructor(private gl: WebGL2RenderingContext, canvas: HTMLCanvasElement) {
    this.accum = this.tex(gl, canvas.width, canvas.height, gl.RGBA16F);
    this.reveal = this.tex(gl, canvas.width, canvas.height, gl.R8);
    this.fbo = gl.createFramebuffer()!;
    gl.bindFramebuffer(gl.FRAMEBUFFER, this.fbo);
    gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, this.accum, 0);
    gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT1, gl.TEXTURE_2D, this.reveal, 0);
    gl.drawBuffers([gl.COLOR_ATTACHMENT0, gl.COLOR_ATTACHMENT1]);
  }
  beginAccum(gl: WebGL2RenderingContext){
    gl.bindFramebuffer(gl.FRAMEBUFFER, this.fbo);
    gl.clearBufferfv(gl.COLOR, 0, [0,0,0,0]); gl.clearBufferfv(gl.COLOR, 1, [1,0,0,0]);
    gl.enable(gl.DEPTH_TEST); gl.depthMask(false);
    gl.enable(gl.BLEND);
    gl.blendFunci(0, gl.ONE, gl.ONE);              // accum: additive
    gl.blendFunci(1, gl.ZERO, gl.ONE_MINUS_SRC_COLOR); // reveal: product
  }
  composite(gl: WebGL2RenderingContext){ /* bind default FBO, draw fullscreen quad blending accum/reveal */ }
  private tex(gl: WebGL2RenderingContext,w:number,h:number,fmt:number){ const t=gl.createTexture()!; gl.bindTexture(gl.TEXTURE_2D,t); gl.texStorage2D(gl.TEXTURE_2D,1,fmt,w,h); return t; }
}

// Save/restore the exact subset of GL state Mapbox relies on, so we never corrupt the map.
export function saveGLState(gl: WebGL2RenderingContext){
  return { fbo: gl.getParameter(gl.FRAMEBUFFER_BINDING), blend: gl.isEnabled(gl.BLEND), depth: gl.isEnabled(gl.DEPTH_TEST), depthMask: gl.getParameter(gl.DEPTH_WRITEMASK) };
}
export function restoreGLState(gl: WebGL2RenderingContext, s: any){
  gl.bindFramebuffer(gl.FRAMEBUFFER, s.fbo);
  s.blend ? gl.enable(gl.BLEND) : gl.disable(gl.BLEND);
  s.depth ? gl.enable(gl.DEPTH_TEST) : gl.disable(gl.DEPTH_TEST);
  gl.depthMask(s.depthMask);
}

import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export function Tour({ url }: { url: string }) {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const renderer = new THREE.WebGLRenderer();
    const scene = new THREE.Scene();
    loadModel(url).then(m => scene.add(m));
    ref.current!.appendChild(renderer.domElement);
    const loop = () => { renderer.render(scene, camera); requestAnimationFrame(loop); };
    loop();
