import { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { disposeScene } from './dispose';
import { assetCache } from './cache';

export function Tour({ url }: { url: string }) {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    let raf = 0; let disposed = false;
    const renderer = new THREE.WebGLRenderer();
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera();
    const host = ref.current!;
    host.appendChild(renderer.domElement);
    loadModel(url, assetCache).then(m => { if (!disposed) scene.add(m); });
    const loop = () => { renderer.render(scene, camera); raf = requestAnimationFrame(loop); };
    raf = requestAnimationFrame(loop);
    return () => {
      disposed = true;
      cancelAnimationFrame(raf);
      disposeScene(scene, assetCache);
      renderer.dispose();
      renderer.forceContextLoss();
      host.removeChild(renderer.domElement);
    };
  }, [url]);
  return <div ref={ref} />;
}

import * as THREE from 'three';
import { AssetCache } from './cache';

export function disposeScene(scene: THREE.Scene, cache: AssetCache) {
  scene.traverse((o) => {
    const mesh = o as THREE.Mesh;
    if (mesh.geometry && !cache.isShared(mesh.geometry.uuid)) mesh.geometry.dispose();
    const mats = Array.isArray(mesh.material) ? mesh.material : mesh.material ? [mesh.material] : [];
    for (const m of mats) {
      for (const key of Object.keys(m)) { const v = (m as any)[key]; if (v && v.isTexture && !cache.isShared(v.uuid)) v.dispose(); }
      if (!cache.isShared(m.uuid)) m.dispose();
    }
  });
  scene.clear();
}

// Ref-counted shared asset cache: skybox, common props reused across listings.
export class AssetCache {
  private refs = new Map<string, number>();
  acquire(uuid: string){ this.refs.set(uuid, (this.refs.get(uuid) ?? 0) + 1); }
  release(uuid: string){ const n=(this.refs.get(uuid) ?? 1)-1; n<=0 ? this.refs.delete(uuid) : this.refs.set(uuid,n); }
  isShared(uuid: string){ return (this.refs.get(uuid) ?? 0) > 0; }
}
export const assetCache = new AssetCache();

import { forceSimulation, forceManyBody, forceLink } from 'd3-force-3d';

export function layout(nodes: any[], links: any[], onTick: (n:any[])=>void) {
  const sim = forceSimulation(nodes, 3)
    .force('charge', forceManyBody().strength(-30))
    .force('link', forceLink(links).distance(20));
  sim.on('tick', () => onTick(nodes)); // copies 80k*3 floats to GPU each tick
}

export class GpuLayout {
  private pos: GPUBuffer; private vel: GPUBuffer; private edges: GPUBuffer;
  constructor(private device: GPUDevice, init: Float32Array, edges: Uint32Array, private pipe: GPUComputePipeline, private bg: GPUBindGroup) {
    this.pos = this.storage(init); this.vel = this.storage(new Float32Array(init.length)); this.edges = this.storageU(edges);
  }
  step(encoder: GPUCommandEncoder, nodeCount: number) {
    const pass = encoder.beginComputePass();
    pass.setPipeline(this.pipe); pass.setBindGroup(0, this.bg);
    pass.dispatchWorkgroups(Math.ceil(nodeCount / 64));
    pass.end();
  }
  positionBuffer(){ return this.pos; } // bound directly as vertex buffer
  private storage(d: Float32Array){ const b=this.device.createBuffer({size:d.byteLength,usage:GPUBufferUsage.STORAGE|GPUBufferUsage.VERTEX|GPUBufferUsage.COPY_DST}); this.device.queue.writeBuffer(b,0,d); return b; }
  private storageU(d: Uint32Array){ const b=this.device.createBuffer({size:d.byteLength,usage:GPUBufferUsage.STORAGE|GPUBufferUsage.COPY_DST}); this.device.queue.writeBuffer(b,0,d); return b; }
}

@group(0) @binding(0) var<storage, read_write> pos: array<vec3<f32>>;
@group(0) @binding(1) var<storage, read_write> vel: array<vec3<f32>>;
@group(0) @binding(2) var<uniform> params: Params;
struct Params { count: u32, dt: f32, charge: f32, _pad: f32 };

@compute @workgroup_size(64)
fn main(@builtin(global_invocation_id) gid: vec3<u32>) {
  let i = gid.x; if (i >= params.count) { return; }
  var f = vec3<f32>(0.0);
  // sampled repulsion against a strided subset for O(n*k) cost
  for (var j: u32 = i % 32u; j < params.count; j = j + 32u) {
    if (j == i) { continue; }
    let d = pos[i] - pos[j];
    let r2 = max(dot(d,d), 0.01);
    f = f + normalize(d) * (params.charge / r2);
  }
  vel[i] = (vel[i] + f * params.dt) * 0.9; // damping
  pos[i] = pos[i] + vel[i] * params.dt;
}

export async function getDevice(): Promise<GPUDevice | null> {
  if (!('gpu' in navigator)) return null;
  const adapter = await navigator.gpu.requestAdapter();
  return adapter ? adapter.requestDevice() : null;
}
export function fallbackNotice(host: HTMLElement){ host.textContent = 'This graph view requires a WebGPU-capable browser (Chrome 113+, Edge).'; }

import * as THREE from 'three';

export function buildParcel(fillGeom: THREE.BufferGeometry, lineGeom: THREE.BufferGeometry) {
  const fill = new THREE.Mesh(fillGeom, new THREE.MeshBasicMaterial({ color: 0xddeeff, transparent: true, opacity: 0.4 }));
  const line = new THREE.LineSegments(lineGeom, new THREE.LineBasicMaterial({ color: 0x003366 }));
  // fill and line occupy the same plane -> z-fight
  return [fill, line];
}

import * as THREE from 'three';

export function buildParcel(fillGeom: THREE.BufferGeometry, lineGeom: THREE.BufferGeometry) {
  const fillMat = new THREE.MeshBasicMaterial({ color: 0xddeeff, transparent: true, opacity: 0.4 });
  fillMat.polygonOffset = true;
  fillMat.polygonOffsetFactor = 1.0;  // push fills away from camera in slope-scaled depth
  fillMat.polygonOffsetUnits = 1.0;
  fillMat.depthWrite = true;
  const fill = new THREE.Mesh(fillGeom, fillMat);
  fill.renderOrder = 0;

  const lineMat = new THREE.LineBasicMaterial({ color: 0x003366 });
  lineMat.depthTest = true; lineMat.depthWrite = false;
  const line = new THREE.LineSegments(lineGeom, lineMat);
  line.renderOrder = 1; // drawn after fills, wins the depth tie
  return [fill, line];
}

import * as THREE from 'three';

// Enable logarithmic depth and a clip-space bias so the offset is zoom-stable.
export function configureRenderer(renderer: THREE.WebGLRenderer) {
  renderer.capabilities.logarithmicDepthBuffer = true;
}
export function biasFor(zoom: number) {
  // polygon offset is in slope-scaled units; with log depth a constant factor is stable across zoom
  return { factor: 1.0, units: 1.0 };
}

import * as THREE from 'three';
// Ensure deterministic draw order: opaque fills, then transparent overlay, then lines.
export function sortParcels(scene: THREE.Scene) {
  scene.children.sort((a,b)=> (a.renderOrder ?? 0) - (b.renderOrder ?? 0));
}

