import { useEffect, useRef } from 'react';
import { ScatterGL } from './ScatterGL';
import { SpatialHash } from './spatial';

export function Scatter({ rows }: { rows: Pt[] }) {
  const ref = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const gl = new ScatterGL(ref.current!, rows);
    const hash = new SpatialHash(rows, 16);
    gl.onView((vt) => gl.draw(vt));
    ref.current!.addEventListener('mousemove', (e) => {
      const [dx, dy] = gl.screenToData(e.offsetX, e.offsetY);
      const id = hash.nearest(dx, dy);
      gl.setTooltip(id);
    });
    return () => gl.dispose();
  }, [rows]);
  return <canvas ref={ref} width={800} height={600} />;
}

export class ScatterGL {
  private gl: WebGL2RenderingContext;
  constructor(canvas: HTMLCanvasElement, rows: Pt[]) {
    this.gl = canvas.getContext('webgl2')!;
    const inst = new Float32Array(rows.length * 6); // x,y,size,r,g,b
    rows.forEach((p,i)=>{ inst.set([p.a,p.b,p.m, ...catColor(p.cat)], i*6); });
    this.uploadInstances(inst);
  }
  draw(viewTransform: Float32Array) {
    const gl = this.gl;
    gl.uniformMatrix3fv(this.uView, false, viewTransform); // zoom/pan only updates this
    gl.drawArraysInstanced(gl.TRIANGLE_STRIP, 0, 4, this.count);
  }
  screenToData(x:number,y:number): [number,number]{ /* inverse of view transform */ return [x,y]; }
  setTooltip(id:number){ /* update overlay */ }
  private uploadInstances(_d: Float32Array){}
  private uView = 0 as any; private count = 0;
  dispose(){}
}

#version 300 es
precision mediump float;
in vec2 vLocal; in vec3 vColor;
out vec4 frag;
void main(){
  float d = length(vLocal); // 0..1 within the quad
  float aa = fwidth(d);
  float a = 1.0 - smoothstep(0.5 - aa, 0.5, d); // crisp anti-aliased circle
  if (a <= 0.0) discard;
  frag = vec4(vColor, a);
}

export class SpatialHash {
  private cells = new Map<string, number[]>();
  constructor(private rows: Pt[], private cell: number) {
    rows.forEach((p,i)=>{ const k=this.key(p.a,p.b); (this.cells.get(k) ?? this.cells.set(k,[]).get(k)!).push(i); });
  }
  nearest(x:number,y:number): number {
    let best=-1, bd=Infinity;
    for (let gx=-1;gx<=1;gx++) for (let gy=-1;gy<=1;gy++) for (const i of this.cells.get(this.key(x+gx*this.cell,y+gy*this.cell)) ?? []) {
      const dx=this.rows[i].a-x, dy=this.rows[i].b-y, d=dx*dx+dy*dy; if (d<bd){bd=d;best=i;}
    }
    return best;
  }
  private key(x:number,y:number){ return `${Math.floor(x/this.cell)},${Math.floor(y/this.cell)}`; }
}

import * as THREE from 'three';

export function pick(raycaster: THREE.Raycaster, scene: THREE.Scene): string | null {
  const hits = raycaster.intersectObjects(scene.children, true); // 400k components
  const o = hits[0]?.object;
  return o ? (o.userData.guid as string) : null;
}

import * as THREE from 'three';

export class GpuPicker {
  private target = new THREE.WebGLRenderTarget(1, 1);
  private pixel = new Uint8Array(4);
  constructor(private renderer: THREE.WebGLRenderer, private idScene: THREE.Scene, private guidByIndex: string[]) {}

  pick(x: number, y: number, camera: THREE.Camera): string | null {
    const cam = camera.clone() as THREE.PerspectiveCamera;
    const dpr = this.renderer.getPixelRatio();
    // 1x1 view offset so we only rasterize the pixel under the cursor
    cam.setViewOffset(this.renderer.domElement.width, this.renderer.domElement.height, x*dpr|0, y*dpr|0, 1, 1);
    this.renderer.setRenderTarget(this.target);
    this.renderer.render(this.idScene, cam);
    this.renderer.readRenderTargetPixels(this.target, 0, 0, 1, 1, this.pixel);
    this.renderer.setRenderTarget(null);
    const id = this.pixel[0] | (this.pixel[1] << 8) | (this.pixel[2] << 16);
    return id === 0xffffff ? null : (this.guidByIndex[id] ?? null);
  }
}

import * as THREE from 'three';

// Encodes a per-instance/per-component integer ID into RGB.
export function makeIdMaterial(): THREE.ShaderMaterial {
  return new THREE.ShaderMaterial({
    vertexShader: `attribute float aId; varying float vId; void main(){ vId=aId; gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0); }`,
    fragmentShader: `varying float vId; void main(){ float id=vId; vec3 c=vec3(mod(id,256.0), mod(floor(id/256.0),256.0), floor(id/65536.0))/255.0; gl_FragColor=vec4(c,1.0); }`,
  });
}

import * as THREE from 'three';
import { makeIdMaterial } from './idMaterial';

// Builds a parallel scene where geometry carries an aId attribute; reused for every pick.
export function buildIdScene(geoms: { geom: THREE.BufferGeometry; baseId: number }[]): { scene: THREE.Scene; guidByIndex: string[] } {
  const scene = new THREE.Scene();
  const guidByIndex: string[] = [];
  const mat = makeIdMaterial();
  for (const g of geoms) {
    const count = g.geom.getAttribute('position').count;
    const ids = new Float32Array(count).fill(g.baseId);
    g.geom.setAttribute('aId', new THREE.BufferAttribute(ids, 1));
    scene.add(new THREE.Mesh(g.geom, mat));
  }
  return { scene, guidByIndex };
}

