export function makeLoader(renderer: any) {
  const ktx2 = new KTX2Loader().setTranscoderPath('/basis/').detectSupport(renderer);
  const loader = new GLTFLoader();
  loader.setKTX2Loader(ktx2);
  loader.setMeshoptDecoder(MeshoptDecoder);
  return loader;
}

export async function loadProduct(loader: GLTFLoader, lowUrl: string, highUrl: string, onLow: (m:any)=>void, onHigh: (m:any)=>void) {
  loader.load(lowUrl, (g) => onLow(g.scene));        // instant low-res paint
  loader.load(highUrl, (g) => onHigh(g.scene));      // streams in, swaps when ready
}

// Build step: compress geometry with Meshopt and textures to KTX2, emit a low-res LOD.
import { execFileSync } from 'child_process';
export function encode(input: string) {
  // gltfpack: meshopt geometry + KTX2/Basis textures
  execFileSync('gltfpack', ['-i', input, '-o', input.replace('.gltf','.high.glb'), '-cc', '-tc']);
  execFileSync('gltfpack', ['-i', input, '-o', input.replace('.gltf','.low.glb'), '-cc', '-tc', '-si', '0.2']); // 20% simplify
}

import { useEffect, useRef } from 'react';
import { makeLoader, loadProduct } from './load';

export function Viewer({ low, high, renderer, scene }: any) {
  const current = useRef<any>(null);
  useEffect(() => {
    const loader = makeLoader(renderer);
    loadProduct(loader, low, high,
      (m) => { current.current = m; scene.add(m); },
      (m) => { if (current.current) scene.remove(current.current); current.current = m; scene.add(m); });
  }, [low, high]);
  return null;
}

