export function loadLegacy(url: string, onReady:(m:any)=>void){ new GLTFLoader().load(url, g=>onReady(g.scene)); }

export function selectLod(dist: number): number {
  if (dist < 20) return 0;
  if (dist < 60) return 1;
  return 2; // hard snap at each threshold -> visible pop
}

export function updateFoliage(instances: Instance[], camPos: Vec3) {
  for (const it of instances) it.lod = selectLod(distance(it.pos, camPos));
}

export interface LodState { lod: number; target: number; t: number; } // t in [0,1] transition progress

export function updateFoliage(states: LodState[], dists: Float32Array, dt: number) {
  for (let i = 0; i < states.length; i++) {
    const s = states[i];
    const desired = lodForDistanceHysteresis(dists[i], s.lod);
    if (desired !== s.target) { s.target = desired; s.t = 0; }
    if (s.target !== s.lod) {
      s.t = Math.min(1, s.t + dt / 0.25); // 250ms transition
      if (s.t >= 1) { s.lod = s.target; s.t = 0; }
    }
  }
}

function lodForDistanceHysteresis(d: number, current: number): number {
  // bands with 5m hysteresis to avoid boundary flicker
  const up = [25, 65]; const down = [15, 55];
  if (current === 0) return d > up[0] ? 1 : 0;
  if (current === 1) return d > up[1] ? 2 : (d < down[0] ? 0 : 1);
  return d < down[1] ? 1 : 2;
}

#version 300 es
precision highp float;
in float vTransition;  // 0..1 progress for this instance
in float vHash;        // stable per-instance hash
in vec2 vScreen;
out vec4 frag;
float dither(vec2 p){ return fract(sin(dot(p, vec2(12.9898,78.233))) * 43758.5453); }
void main(){
  // stochastic discard: pixels fade in/out by comparing a screen dither to transition progress
  float threshold = dither(gl_FragCoord.xy + vHash);
  if (threshold > vTransition) discard;
  frag = vec4(0.2, 0.5, 0.15, 1.0);
}

// Pack transition + hash into the existing instance attributes; no duplicate geometry.
export function writeTransition(buf: Float32Array, i: number, t: number, hash: number) {
  buf[i*2] = t; buf[i*2+1] = hash;
}

export class Viewport {
  constructor(private renderer: THREE.WebGLRenderer, private rt: THREE.WebGLRenderTarget, private el: HTMLElement) {
    new ResizeObserver(() => this.onResize()).observe(el);
  }
  onResize() {
    const w = this.el.clientWidth, h = this.el.clientHeight;
    this.renderer.setSize(w, h);                 // reallocates drawing buffer
    this.rt.setSize(w, h);                        // reallocates render target each event
  }
}

export class Viewport {
  private dirty = false; private rafId = 0;
  constructor(private renderer: THREE.WebGLRenderer, private rt: THREE.WebGLRenderTarget, private el: HTMLElement) {
    new ResizeObserver(() => this.markDirty()).observe(el);
    matchMedia('(resolution: 1dppx)').addEventListener('change', () => this.markDirty());
  }
  private markDirty() { this.dirty = true; if (!this.rafId) this.rafId = requestAnimationFrame(() => this.apply()); }
  private apply() {
    this.rafId = 0;
    if (!this.dirty) return;
    this.dirty = false;
    const dpr = Math.min(window.devicePixelRatio, 2);
    const w = this.el.clientWidth, h = this.el.clientHeight; // freshest size
    this.renderer.setPixelRatio(dpr);
    this.renderer.setSize(w, h, false);
    this.rt.setSize(Math.floor(w * dpr), Math.floor(h * dpr));
    // if more resize events arrived during apply, schedule one more frame
    if (this.dirty) this.rafId = requestAnimationFrame(() => this.apply());
  }
  dispose() { if (this.rafId) cancelAnimationFrame(this.rafId); }
}

// Watch DPR changes across monitor moves and re-arm the matchMedia at each new ratio.
export function watchDpr(onChange: () => void) {
  let mq = matchMedia(`(resolution: ${window.devicePixelRatio}dppx)`);
  const handler = () => { onChange(); mq.removeEventListener('change', handler); mq = matchMedia(`(resolution: ${window.devicePixelRatio}dppx)`); mq.addEventListener('change', handler); };
  mq.addEventListener('change', handler);
}

// Optional global guard: cap total target reallocations across all viewports per frame.
let thisFrame = 0; let frame = -1;
export function allowRealloc(now: number): boolean {
  if (now !== frame) { frame = now; thisFrame = 0; }
  return thisFrame++ < 4; // at most the 4 viewports per frame
}

export function render(scene: THREE.Scene, camera: THREE.Camera, renderer: THREE.WebGLRenderer) {
  // three.js does frustum culling per-object, but 60k objects still iterate;
  // occluded racks behind walls are fully shaded.
  renderer.render(scene, camera);
}

export class Culler {
  private queries = new Map<string, WebGLQuery>();
  private lastVisible = new Set<string>();
  constructor(private gl: WebGL2RenderingContext, private clusters: Cluster[], public enabled = true) {}

  cull(camera: THREE.Camera): Cluster[] {
    if (!this.enabled) return this.clusters;
    const frustum = makeFrustum(camera);
    const candidates = this.clusters.filter(c => frustum.intersectsBox(c.bounds)); // CPU frustum cull
    const visible = candidates.filter(c => this.lastVisible.has(c.id) || this.queries.size === 0); // last-frame result
    this.issueQueries(candidates); // for next frame
    return visible.length ? visible : candidates; // first frame: draw all candidates
  }

  collectResults() {
    const next = new Set<string>();
    for (const [id, q] of this.queries) {
      if (this.gl.getQueryParameter(q, this.gl.QUERY_RESULT_AVAILABLE)) {
        if (this.gl.getQueryParameter(q, this.gl.QUERY_RESULT) > 0) next.add(id);
      } else next.add(id); // not ready -> assume visible to avoid pop-out
    }
    this.lastVisible = next;
  }
  private issueQueries(_c: Cluster[]) { /* render bounds with depth test, sample count via beginQuery */ }
}

// Cheap depth-only pass of occluders (walls/floors) for occlusion queries to test against.
export function depthPrepass(gl: WebGL2RenderingContext, occluders: Mesh[], depthProg: WebGLProgram) {
  gl.colorMask(false, false, false, false);
  gl.depthMask(true);
  gl.useProgram(depthProg);
  for (const o of occluders) o.draw(gl);
  gl.colorMask(true, true, true, true);
}

import { Culler } from './Culler';

export function render(culler: Culler, camera: THREE.Camera, draw: (clusters: Cluster[]) => void, overlay: () => void) {
  culler.collectResults();        // read last frame's query results
  const visible = culler.cull(camera);
  draw(visible);
  overlay();                      // AGV overlay always drawn, never culled
}

