export async function renderThumbnail(job: { url: string; format: string }): Promise<Buffer> {
  const width = 512, height = 512;
  const context = gl(width, height, { preserveDrawingBuffer: true }); // headless EGL/software
  const renderer = new THREE.WebGLRenderer({ context, antialias: true });
  renderer.setSize(width, height);
  const scene = new THREE.Scene();
  scene.add(new THREE.HemisphereLight(0xffffff, 0x444444, 1.0));
  const model = await loadAny(job.url, job.format);
  scene.add(model);
  const camera = frameModel(model, width / height); // deterministic framing
  renderer.render(scene, camera);
  const pixels = new Uint8Array(width * height * 4);
  (renderer.getContext() as any).readPixels(0, 0, width, height, context.RGBA, context.UNSIGNED_BYTE, pixels);
  renderer.dispose();
  return encodePng(flipY(pixels, width, height));
}

import * as THREE from 'three';

// Deterministic camera: fit the model's bounding sphere at fixed azimuth/elevation.
export function frameModel(model: THREE.Object3D, aspect: number): THREE.PerspectiveCamera {
  const box = new THREE.Box3().setFromObject(model);
  const sphere = box.getBoundingSphere(new THREE.Sphere());
  const fov = 35; const cam = new THREE.PerspectiveCamera(fov, aspect, 0.1, 1000);
  const dist = sphere.radius / Math.sin((fov * Math.PI / 180) / 2) * 1.2;
  const az = Math.PI / 4, el = Math.PI / 6; // fixed angles for reproducibility
  cam.position.set(sphere.center.x + dist*Math.cos(el)*Math.cos(az), sphere.center.y + dist*Math.sin(el), sphere.center.z + dist*Math.cos(el)*Math.sin(az));
  cam.lookAt(sphere.center);
  return cam;
}

