export async function consume(job: { id: string; url: string; format: string }) {
  const key = `thumb/${job.id}.png`;
  if (await store.exists(key)) return; // content-addressed cache hit
  for (let attempt = 0; attempt < 3; attempt++) {
    try { const png = await renderThumbnail(job); await store.put(key, png); return; }
    catch (e) { await new Promise(r => setTimeout(r, 500 * 2 ** attempt)); }
  }
  await store.markFailed(job.id);
}

