export class ObjectLayer {
  private mesh: THREE.InstancedMesh;
  private ecef: Float64Array; // authoritative doubles
  private dummy = new THREE.Object3D();
  constructor(scene: THREE.Scene, geom: THREE.BufferGeometry, mat: THREE.Material, objs: {ecef:[number,number,number]}[]) {
    this.mesh = new THREE.InstancedMesh(geom, mat, objs.length);
    this.ecef = new Float64Array(objs.length * 3);
    objs.forEach((o,i)=> this.ecef.set(o.ecef, i*3));
    scene.add(this.mesh);
  }
  update(origin: FloatingOrigin) {
    const c = origin.cameraEcef;
    for (let i = 0; i < this.mesh.count; i++) {
      // double subtraction, then float32 cast happens inside setMatrixAt
      this.dummy.position.set(this.ecef[i*3]-c[0], this.ecef[i*3+1]-c[1], this.ecef[i*3+2]-c[2]);
      this.dummy.updateMatrix();
      this.mesh.setMatrixAt(i, this.dummy.matrix);
    }
    this.mesh.instanceMatrix.needsUpdate = true;
  }
}

