export class DynamicResolution {
  private scale = 1.0; private ema = 16.6;
  constructor(private min = 0.5, private max = 1.0, private step = 0.05, private targetMs = 16.6) {}
  update(frameMs: number): number {
    this.ema = this.ema * 0.8 + frameMs * 0.2; // smooth
    if (this.ema > this.targetMs * 1.05) this.scale = Math.max(this.min, this.scale - this.step);
    else if (this.ema < this.targetMs * 0.85) this.scale = Math.min(this.max, this.scale + this.step);
    return this.scale;
  }
  current(){ return this.scale; }
}

import { DynamicResolution } from './DynamicResolution';

export function makeRenderLoop(renderer: THREE.WebGLRenderer, scene: THREE.Scene, camera: THREE.Camera, rt: THREE.WebGLRenderTarget, overlay: () => void, baseW: number, baseH: number) {
  const dr = new DynamicResolution();
  let last = performance.now();
  const loop = (t: number) => {
    const dt = t - last; last = t;
    const scale = dr.update(dt);
    rt.setSize(Math.floor(baseW * scale), Math.floor(baseH * scale));
    renderer.setRenderTarget(rt);
    renderer.render(scene, camera);          // 3D at scaled resolution
    renderer.setRenderTarget(null);
    blitUpscale(renderer, rt);               // upsample to screen
    overlay();                               // overlay at native resolution
    requestAnimationFrame(loop);
  };
  requestAnimationFrame(loop);
}

