// WebGL GLSL ray-march (authoritative today)
uniform sampler3D uVolume; uniform float uStep;
varying vec3 vRayOrigin; varying vec3 vRayDir;
void main(){
  vec3 p = vRayOrigin; float acc = 0.0;
  for (int i = 0; i < 256; i++) {
    float d = texture(uVolume, p).r;
    acc += d * uStep; p += vRayDir * uStep;
    if (acc > 1.0) break;
  }
  gl_FragColor = vec4(vec3(acc), 1.0);
}

// Single source of truth for the ray-march; emits both GLSL and WGSL.
export const raymarch = {
  body: `
    var acc = 0.0;
    var p = rayOrigin;
    for (var i = 0; i < STEPS; i = i + 1) {
      let d = SAMPLE3D(uVolume, p).r;
      acc = acc + d * uStep;
      p = p + rayDir * uStep;
      if (acc > 1.0) { break; }
    }
    OUT = vec4(vec3(acc), 1.0);
  `,
  steps: 256,
};

import { raymarch } from './raymarch.shader';

export function toWGSL(): string {
  return raymarch.body
    .replace(/SAMPLE3D\(([^,]+),([^)]+)\)/g, 'textureSample($1, vSampler, $2)')
    .replace('OUT', 'output')
    .replace('STEPS', String(raymarch.steps));
}
export function toGLSL(): string {
  return raymarch.body
    .replace(/SAMPLE3D\(([^,]+),([^)]+)\)/g, 'texture($1, $2)')
    .replace('OUT', 'gl_FragColor')
    .replace('var ', 'float ').replace(/let /g, 'float ')
    .replace('STEPS', String(raymarch.steps));
}

