export class HexLayer {
  private cache = new Map<string, { bins: any[]; version: string }>();
  constructor(private fetchTile: (z:number,x:number,y:number)=>Promise<any>) {}

  async update(visibleTiles: {z:number;x:number;y:number}[]) {
    const needed = visibleTiles.filter(t => !this.cache.has(this.key(t)));
    const fetched = await Promise.all(needed.map(t => this.fetchTile(t.z, t.x, t.y).then(r => ({ t, r }))));
    for (const { t, r } of fetched) this.cache.set(this.key(t), r);
    return visibleTiles.flatMap(t => this.cache.get(this.key(t))!.bins);
  }
  invalidate(zoom: number, version: string) {
    for (const [k, v] of this.cache) if (k.startsWith(`${zoom}:`) && v.version !== version) this.cache.delete(k);
  }
  private key(t:{z:number;x:number;y:number}){ return `${t.z}:${t.x}:${t.y}`; }
}

