type Reg = { tabId: string; want: number; focused: boolean; ts: number };

export class BudgetCoordinator {
  private ch = new BroadcastChannel('gpu-budget');
  private tabs = new Map<string, Reg>();
  private tabId = crypto.randomUUID();
  constructor(private capBytes: number, private onGrant: (bytes: number) => void) {
    this.ch.onmessage = (e) => this.handle(e.data);
    setInterval(() => this.heartbeat(), 1000);
  }
  register(want: number, focused: boolean) {
    const reg = { tabId: this.tabId, want, focused, ts: Date.now() };
    this.tabs.set(this.tabId, reg);
    this.ch.postMessage({ type: 'register', reg });
    this.recompute();
  }
  private handle(msg: any) {
    if (msg.type === 'register' || msg.type === 'heartbeat') { this.tabs.set(msg.reg.tabId, msg.reg); this.recompute(); }
    if (msg.type === 'bye') { this.tabs.delete(msg.tabId); this.recompute(); }
  }
  private recompute() {
    // prune dead tabs (no heartbeat in 3s)
    const now = Date.now();
    for (const [id, r] of this.tabs) if (now - r.ts > 3000) this.tabs.delete(id);
    const focused = [...this.tabs.values()].filter(r => r.focused);
    const others = [...this.tabs.values()].filter(r => !r.focused);
    let grant = 0;
    const mine = this.tabs.get(this.tabId);
    if (mine?.focused) grant = Math.min(mine.want, this.capBytes - others.length * minShare());
    else grant = Math.max(minShare(), (this.capBytes - focusedTotal(focused)) / Math.max(1, others.length));
    this.onGrant(grant);
  }
  private heartbeat(){ const r=this.tabs.get(this.tabId); if(r){ r.ts=Date.now(); this.ch.postMessage({type:'heartbeat',reg:r}); } }
}
function minShare(){ return 32*1024*1024; }
function focusedTotal(f: Reg[]){ return f.reduce((s,r)=>s+r.want,0); }

import { BudgetCoordinator } from './BudgetCoordinator';

export class Scene {
  private coord: BudgetCoordinator;
  constructor(canvas: HTMLCanvasElement) {
    this.renderer = new THREE.WebGLRenderer({ canvas });
    this.coord = new BudgetCoordinator(256*1024*1024, (bytes) => this.applyBudget(bytes));
    this.coord.register(192*1024*1024, !document.hidden);
    document.addEventListener('visibilitychange', () => this.coord.register(192*1024*1024, !document.hidden));
  }
  applyBudget(bytes: number) {
    const level = bytes < 64*1024*1024 ? 'low' : bytes < 128*1024*1024 ? 'med' : 'high';
    this.setTextureResolution(level); // downgrade when granted less
  }
  private setTextureResolution(_l: string){}
}

