export class Waveform {
  draw(samples: Float32Array) {
    const pos = new Float32Array(samples.length * 3); // new alloc each frame
    for (let i = 0; i < samples.length; i++) { pos[i*3]=i; pos[i*3+1]=samples[i]; pos[i*3+2]=0; }
    this.geom.setAttribute('position', new THREE.BufferAttribute(pos, 3));
    this.geom.attributes.position.needsUpdate = true; // full re-upload
  }
}

export class Waveform {
  private head = 0;
  constructor(private gl: WebGL2RenderingContext, private vbo: WebGLBuffer, private capacity: number) {
    gl.bindBuffer(gl.ARRAY_BUFFER, vbo);
    gl.bufferData(gl.ARRAY_BUFFER, capacity * 4, gl.DYNAMIC_DRAW); // allocated once
  }
  append(newSamples: Float32Array) {
    const gl = this.gl;
    gl.bindBuffer(gl.ARRAY_BUFFER, this.vbo);
    // write only the new samples at the ring head (sub-upload)
    const end = this.head + newSamples.length;
    if (end <= this.capacity) gl.bufferSubData(gl.ARRAY_BUFFER, this.head*4, newSamples);
    else { const split = this.capacity - this.head; gl.bufferSubData(gl.ARRAY_BUFFER, this.head*4, newSamples.subarray(0,split)); gl.bufferSubData(gl.ARRAY_BUFFER, 0, newSamples.subarray(split)); }
    this.head = end % this.capacity;
  }
  headOffset(){ return this.head; }
}

#version 300 es
layout(location=0) in float aSample;   // y value
layout(location=1) in float aIndex;    // position in ring
uniform float uHead; uniform float uCapacity; uniform float uWidthPx; uniform vec2 uViewport;
void main(){
  float scrollX = mod(aIndex - uHead + uCapacity, uCapacity) / uCapacity; // 0..1 left->right
  vec2 ndc = vec2(scrollX * 2.0 - 1.0, aSample);
  // thicken: offset along screen-space normal by half width (expansion handled with adjacent vertex in full impl)
  gl_Position = vec4(ndc, 0.0, 1.0);
}

