import * as THREE from 'three';

export class CSM {
  cascades: { cam: THREE.OrthographicCamera; map: THREE.WebGLRenderTarget; split: number }[] = [];
  constructor(private sunDir: THREE.Vector3, splits = [0.05, 0.15, 0.4, 1.0], size = 2048) {
    for (const s of splits) this.cascades.push({ cam: new THREE.OrthographicCamera(), map: new THREE.WebGLRenderTarget(size, size), split: s });
  }
  update(viewCam: THREE.PerspectiveCamera) {
    let near = viewCam.near;
    for (const c of this.cascades) {
      const far = viewCam.near + (viewCam.far - viewCam.near) * c.split;
      fitCascade(c.cam, viewCam, near, far, this.sunDir); // tight ortho box for this slice
      snapToTexel(c.cam, c.map.width);                     // stop swimming
      near = far;
    }
  }
}

import * as THREE from 'three';
// Snap the shadow camera's origin to the shadow-map texel grid so shadows don't crawl.
export function snapToTexel(cam: THREE.OrthographicCamera, mapSize: number) {
  const worldUnitsPerTexel = (cam.right - cam.left) / mapSize;
  cam.position.x = Math.round(cam.position.x / worldUnitsPerTexel) * worldUnitsPerTexel;
  cam.position.y = Math.round(cam.position.y / worldUnitsPerTexel) * worldUnitsPerTexel;
  cam.updateProjectionMatrix();
}

#version 300 es
precision highp float;
uniform sampler2D uCascade[4]; uniform float uSplits[4];
in float vViewDepth; in vec4 vShadowCoord[4];
float sampleCascade(int i){ return texture(uCascade[i], vShadowCoord[i].xy).r < vShadowCoord[i].z ? 0.5 : 1.0; }
void main(){
  int idx = 3;
  for (int i = 0; i < 4; i++) { if (vViewDepth < uSplits[i]) { idx = i; break; } }
  float shadow = sampleCascade(idx); // select cascade by depth
  gl_FragColor = vec4(vec3(shadow), 1.0);
}

export function loop(world: AmmoWorld, render: () => void) {
  let last = performance.now();
  const frame = (t: number) => {
    const dt = (t - last) / 1000; last = t; // variable dt
    world.stepSimulation(dt, 1); // non-deterministic across frame rates
    render();
    requestAnimationFrame(frame);
  };
  requestAnimationFrame(frame);
}

export class FixedStep {
  private acc = 0; private stepIndex = 0;
  constructor(private dt = 1/120) {}
  advance(frameSeconds: number, step: (index: number) => void) {
    this.acc += Math.min(frameSeconds, 0.25); // clamp to avoid spiral of death
    while (this.acc >= this.dt) { step(this.stepIndex++); this.acc -= this.dt; }
  }
  alpha(){ return this.acc / this.dt; } // for render interpolation
  index(){ return this.stepIndex; }
}

export interface InputEvent { stepIndex: number; bodyId: number; impulse: [number,number,number]; }

export class EventLog {
  events: InputEvent[] = [];
  constructor(public seed: number) {}
  record(stepIndex: number, bodyId: number, impulse: [number,number,number]) { this.events.push({ stepIndex, bodyId, impulse }); }
  forStep(stepIndex: number) { return this.events.filter(e => e.stepIndex === stepIndex); }
  encode(): string { return btoa(JSON.stringify({ seed: this.seed, events: this.events })); }
  static decode(s: string): EventLog { const o = JSON.parse(atob(s)); const l = new EventLog(o.seed); l.events = o.events; return l; }
}

import { FixedStep } from './FixedStep';
import { EventLog } from './EventLog';

export function run(world: AmmoWorld, log: EventLog, render: (alpha:number)=>void) {
  const fixed = new FixedStep();
  let last = performance.now();
  const frame = (t: number) => {
    fixed.advance((t - last)/1000, (i) => {
      for (const e of log.forStep(i)) world.applyImpulse(e.bodyId, e.impulse); // deterministic input application
      world.stepSimulation(1/120, 0); // exact fixed step, no sub-stepping
    });
    last = t;
    render(fixed.alpha());
    requestAnimationFrame(frame);
  };
  requestAnimationFrame(frame);
}

export async function loadGallery(artworks: Art[]) {
  for (const a of artworks) {
    const tex = await loadTexture(a.url8k); // full 8K each -> 3.1GB total
    a.material.map = tex;
  }
}

export class TextureStreamer {
  private loaded = new Map<string, { level: number; bytes: number; lastUsed: number; tex: THREE.Texture }>();
  private bytes = 0;
  constructor(private capBytes = 1_000_000_000) {}

  async ensure(art: Art, desiredLevel: number) {
    const key = `${art.id}:${desiredLevel}`;
    const cur = this.loaded.get(key);
    if (cur) { cur.lastUsed = performance.now(); return cur.tex; }
    const tex = await loadMip(art, desiredLevel);
    const size = mipBytes(art, desiredLevel);
    while (this.bytes + size > this.capBytes) this.evictLRU();
    this.loaded.set(key, { level: desiredLevel, bytes: size, lastUsed: performance.now(), tex });
    this.bytes += size;
    return tex;
  }
  private evictLRU() {
    let oldest: string | null = null, t = Infinity;
    for (const [k, v] of this.loaded) if (v.lastUsed < t) { t = v.lastUsed; oldest = k; }
    if (oldest) { const e = this.loaded.get(oldest)!; e.tex.dispose(); this.bytes -= e.bytes; this.loaded.delete(oldest); }
  }
}

import * as THREE from 'three';
// Choose mip level from projected screen-space size of the artwork plane.
export function desiredMip(art: Art, camera: THREE.Camera, viewportH: number): number {
  const screenH = projectedHeightPx(art.plane, camera, viewportH);
  const fullTexels = art.fullHeight; // e.g. 8192
  const level = Math.max(0, Math.floor(Math.log2(fullTexels / Math.max(1, screenH))));
  return Math.min(level, art.maxLevel);
}

import * as THREE from 'three';
// Blend the previous mip into the new one over ~200ms to avoid a blur->sharp pop.
export function crossfade(material: THREE.ShaderMaterial, prev: THREE.Texture, next: THREE.Texture, onDone: ()=>void) {
  material.uniforms.uPrev.value = prev; material.uniforms.uNext.value = next;
  let t = 0; const step = () => { t += 1/12; material.uniforms.uMix.value = Math.min(1,t); if (t<1) requestAnimationFrame(step); else onDone(); };
  requestAnimationFrame(step);
}

export function draw(gl: WebGL2RenderingContext, particles: Particle[]) {
  gl.enable(gl.BLEND);
  gl.blendFunc(gl.SRC_ALPHA, gl.ONE); // additive
  for (const p of particles) p.draw(gl); // spawn order, depth ignored
}

// Approximate radix bucket sort by quantized camera-space depth (near-linear, mobile-friendly).
export function bucketByDepth(particles: Float32Array, count: number, camZ: (i:number)=>number, bins = 64): Uint32Array {
  const counts = new Uint32Array(bins);
  const bin = new Uint8Array(count);
  let min = Infinity, max = -Infinity;
  for (let i = 0; i < count; i++) { const d = camZ(i); if (d<min)min=d; if (d>max)max=d; }
  const span = (max - min) || 1;
  for (let i = 0; i < count; i++) { const b = Math.min(bins-1, ((camZ(i)-min)/span*bins)|0); bin[i]=b; counts[b]++; }
  const offsets = new Uint32Array(bins); for (let b=1;b<bins;b++) offsets[b]=offsets[b-1]+counts[b-1];
  const order = new Uint32Array(count); const cur = offsets.slice();
  for (let i = 0; i < count; i++) { order[cur[bin[i]]++] = i; } // back-to-front by bin
  return order;
}

import { bucketByDepth } from './depthSort';

export function draw(gl: WebGL2RenderingContext, smoke: ParticleSet, cores: ParticleSet, camZ:(set:ParticleSet,i:number)=>number) {
  // alpha smoke: depth-sorted, back-to-front
  const order = bucketByDepth(smoke.data, smoke.count, (i)=>camZ(smoke,i));
  gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
  smoke.drawInstanced(gl, order); // one instanced call, ordered
  // additive cores: order-independent, draw unsorted
  gl.blendFunc(gl.SRC_ALPHA, gl.ONE);
  cores.drawInstanced(gl);
}

// Instanced particle set reorders its instance buffer by the provided order array before drawing.
export class ParticleSet {
  drawInstanced(gl: WebGL2RenderingContext, order?: Uint32Array) {
    if (order) this.reorderInstances(order); // write sorted instance attributes
    gl.drawArraysInstanced(gl.TRIANGLE_STRIP, 0, 4, this.count);
  }
  reorderInstances(_o: Uint32Array){}
  count = 0;
}

export function decimate(vertices: Float32Array, indices: Uint32Array, target: number): { v: Float32Array; i: Uint32Array } {
  // pure JS quadric error metric collapse -> ~11s for 4M tris on main thread
  let mesh = buildMesh(vertices, indices);
  while (mesh.triangleCount > target) mesh.collapseCheapestEdge(); // O(n log n) but in JS, blocking
  return mesh.export();
}

import initSimplify from './simplify_wasm';

self.onmessage = async (e: MessageEvent) => {
  const { vertices, indices, target, featureWeights } = e.data;
  const wasm = await initSimplify();
  const out = wasm.simplifyWithAttributes(
    new Float32Array(vertices), new Uint32Array(indices), target,
    new Float32Array(featureWeights) // higher weight on margin-line vertices
  );
  (self as any).postMessage({ v: out.vertices, i: out.indices }, [out.vertices.buffer, out.indices.buffer]);
};

export function decimate(vertices: Float32Array, indices: Uint32Array, target: number, featureWeights: Float32Array): Promise<{v:Float32Array;i:Uint32Array}> {
  const worker = new Worker(new URL('./decimate.worker.ts', import.meta.url), { type: 'module' });
  return new Promise((res) => {
    worker.onmessage = (e) => { res(e.data); worker.terminate(); };
    worker.postMessage({ vertices, indices, target, featureWeights }, [vertices.buffer, indices.buffer]);
  });
}

// Mark margin-line vertices with high feature weight so QEM preserves them.
export function featureWeights(vertices: Float32Array, curvature: Float32Array): Float32Array {
  const w = new Float32Array(vertices.length / 3);
  for (let i = 0; i < w.length; i++) w[i] = curvature[i] > 0.6 ? 8.0 : 1.0; // protect high-curvature edges
  return w;
}

export function ssao(gl: WebGL2RenderingContext, depth: WebGLTexture, normal: WebGLTexture) {
  // full-res, 32 samples, no blur, recomputed each frame at native resolution
  gl.useProgram(ssaoProgram);
  gl.uniform1i(uSamples, 32);
  drawFullscreen(gl); // ~12ms at 1080p on mobile -> 18 FPS
}

export class SSAO {
  private halfRT: THREE.WebGLRenderTarget;
  private blurRT: THREE.WebGLRenderTarget;
  constructor(gl: WebGL2RenderingContext, w: number, h: number) {
    this.halfRT = new THREE.WebGLRenderTarget(w/2, h/2); // 1/4 the pixels
    this.blurRT = new THREE.WebGLRenderTarget(w/2, h/2);
  }
  render(gl: WebGL2RenderingContext, depth: WebGLTexture, normal: WebGLTexture) {
    bindTarget(this.halfRT); drawSSAO(gl, depth, normal, 16); // half-res, 16 samples
    bindTarget(this.blurRT); drawBilateralBlur(gl, this.halfRT.texture, depth); // depth-aware denoise
    return this.blurRT.texture; // upsampled at composite
  }
}

#version 300 es
precision highp float;
uniform sampler2D uAO; uniform sampler2D uDepth; uniform vec2 uTexel;
in vec2 vUv; out vec4 frag;
void main(){
  float centerD = texture(uDepth, vUv).r;
  float sum = 0.0; float wsum = 0.0;
  for (int x=-2;x<=2;x++) for (int y=-2;y<=2;y++) {
    vec2 o = vec2(float(x),float(y))*uTexel;
    float d = texture(uDepth, vUv+o).r;
    float w = exp(-abs(d-centerD)*50.0); // depth-aware: don't blur across silhouettes
    sum += texture(uAO, vUv+o).r * w; wsum += w;
  }
  frag = vec4(vec3(sum/wsum), 1.0);
}

// Blend this frame's AO with the previous, reprojected, to stabilize under motion.
export function temporalAccumulate(gl: WebGL2RenderingContext, current: WebGLTexture, history: WebGLTexture, alpha = 0.1) {
  drawBlend(gl, current, history, alpha); // exponential moving average
}
